/* House Dismantle — Study Room Extension (example: constraint-first pipeline)
 *
 * This file was generated by the 3-step pipeline:
 *   1. constraints/study-room.md  →  define spatial rules
 *   2. validate/rules/study-room.js →  enforce them
 *   3. house-study.js              →  build the 3D model (this file)
 */
import * as THREE from 'three';
import { HW2, WALL_H1, WALL_T, FLOOR_H } from './config.js';

export const STUDY_X = HW2 + 1.5;    // 7.5
export const STUDY_Z = 2.8;  // avoid crossWall at z=1.0
export const STUDY_W = 3.0;
export const STUDY_D = 3.0;
export const STUDY_H = WALL_H1;       // 2.8
const STUDY_WALL_T = 0.15;

function box(w, h, d, m) { return new THREE.Mesh(new THREE.BoxGeometry(w, h, d), m); }

export function buildStudy(houseGroup, parts, MATS) {
  function partGrp(name, label, color, deps = []) {
    const g = new THREE.Group(); g.name = name;
    if (!parts.has(name)) {
      parts.set(name, { group: g, label, color, deps, assembled: true, meshArr: [] });
      houseGroup.add(g);
    }
    return parts.get(name).group;
  }
  function addTo(name, mesh) {
    const p = parts.get(name);
    if (p) { p.meshArr.push(mesh); mesh.userData.partName = name; mesh.castShadow = true; mesh.receiveShadow = true; }
  }

  const floorY = FLOOR_H;
  const ceilY = FLOOR_H + STUDY_H;
  const sx = STUDY_X, sz = STUDY_Z;
  const hw = STUDY_W / 2, hd = STUDY_D / 2;

  // ═══════════════════════════════════════════════════════════════
  // STUDY FLOOR
  // ═══════════════════════════════════════════════════════════════
  const floorGrp = partGrp('studyFloor', '书房地板', '#a09078', ['studyWalls']);
  const floorSlab = box(STUDY_W + 0.1, 0.06, STUDY_D + 0.1, MATS.floor);
  floorSlab.position.set(sx, floorY + 0.03, sz);
  addTo('studyFloor', floorSlab); floorGrp.add(floorSlab);

  // ═══════════════════════════════════════════════════════════════
  // STUDY WALLS (3 walls — front, right, back; left shares house wall)
  // ═══════════════════════════════════════════════════════════════
  const wallsGrp = partGrp('studyWalls', '书房屋墙', '#e8dcc8',
    ['studyDoor', 'studyDesk', 'studyBookshelf']);
  const wallMat = MATS.upperWall;

  // Front wall (Z+)
  const wf = box(STUDY_W, STUDY_H, STUDY_WALL_T, wallMat);
  wf.position.set(sx, floorY + STUDY_H / 2, sz + hd);
  addTo('studyWalls', wf); wallsGrp.add(wf);

  // Back wall (Z-)
  const wb = box(STUDY_W, STUDY_H, STUDY_WALL_T, wallMat);
  wb.position.set(sx, floorY + STUDY_H / 2, sz - hd);
  addTo('studyWalls', wb); wallsGrp.add(wb);

  // Right wall (X+), with window opening
  const wr = box(STUDY_WALL_T, STUDY_H, STUDY_D, wallMat);
  wr.position.set(sx + hw, floorY + STUDY_H / 2, sz);
  addTo('studyWalls', wr); wallsGrp.add(wr);

  // Ceiling
  const ceil = box(STUDY_W - STUDY_WALL_T * 2, 0.06, STUDY_D - STUDY_WALL_T * 2, MATS.floor);
  ceil.position.set(sx, ceilY - 0.03, sz);
  addTo('studyWalls', ceil); wallsGrp.add(ceil);

  // ═══════════════════════════════════════════════════════════════
  // STUDY DOOR (in the left opening, connecting to main house)
  // ═══════════════════════════════════════════════════════════════
  const doorGrp = partGrp('studyDoor', '书房门', '#4a2818', ['studyWalls']);
  const doorW = 0.9, doorH = 2.1;
  const doorX = sx - hw; // left wall plane
  const doorY = floorY + doorH / 2;
  const doorZ = sz;

  // Door frame
  for (const dx of [-doorW / 2, doorW / 2]) {
    const f = box(0.06, doorH, 0.04, MATS.door);
    f.position.set(doorX, doorY, doorZ + dx);
    addTo('studyDoor', f); doorGrp.add(f);
  }
  const ft = box(doorW, 0.06, 0.04, MATS.door);
  ft.position.set(doorX, doorY + doorH / 2, doorZ);
  addTo('studyDoor', ft); doorGrp.add(ft);

  // Door panel
  const panel = box(doorW - 0.06, doorH - 0.04, 0.04, MATS.doorPanel || MATS.door);
  panel.position.set(doorX + 0.04, doorY, doorZ);
  addTo('studyDoor', panel); doorGrp.add(panel);

  // ═══════════════════════════════════════════════════════════════
  // STUDY DESK (against front wall)
  // ═══════════════════════════════════════════════════════════════
  const deskGrp = partGrp('studyDesk', '书桌', '#8b6914', ['studyWalls']);
  const deskTop = box(1.8, 0.05, 0.8, MATS.woodLight);
  deskTop.position.set(sx, 1.1, sz + hd - 0.7);
  addTo('studyDesk', deskTop); deskGrp.add(deskTop);

  for (const [lx, lz] of [[-0.7, -0.3], [0.7, -0.3], [-0.7, 0.3], [0.7, 0.3]]) {
    const leg = box(0.06, 0.9, 0.06, MATS.woodDark);
    leg.position.set(sx + lx, 0.55, sz + hd - 0.7 + lz);
    addTo('studyDesk', leg); deskGrp.add(leg);
  }

  // Chair (simple stool)
  const chairSeat = box(0.45, 0.06, 0.45, MATS.woodLight);
  chairSeat.position.set(sx, 0.55, sz + hd - 1.5);
  addTo('studyDesk', chairSeat); deskGrp.add(chairSeat);
  for (const [cx2, cz2] of [[-0.18, -0.18], [0.18, -0.18], [-0.18, 0.18], [0.18, 0.18]]) {
    const cLeg = box(0.04, 0.5, 0.04, MATS.woodDark);
    cLeg.position.set(sx + cx2, 0.25, sz + hd - 1.5 + cz2);
    addTo('studyDesk', cLeg); deskGrp.add(cLeg);
  }

  // ═══════════════════════════════════════════════════════════════
  // BOOKSHELF (against back wall)
  // ═══════════════════════════════════════════════════════════════
  const shelfGrp = partGrp('studyBookshelf', '书架', '#6b4a20', ['studyWalls']);
  const shelfBody = box(1.6, 2.2, 0.3, MATS.woodDark);
  shelfBody.position.set(sx, floorY + 1.1, sz - hd + 0.25);
  addTo('studyBookshelf', shelfBody); shelfGrp.add(shelfBody);

  // Shelves (3 horizontal boards, offset Z to avoid z-fighting with body)
  for (let sh = 0; sh < 3; sh++) {
    const shelf = box(1.4, 0.04, 0.28, MATS.woodLight);
    shelf.position.set(sx, floorY + 0.6 + sh * 0.6, sz - hd + 0.25 + (sh % 2 === 0 ? 0.005 : -0.005));
    addTo('studyBookshelf', shelf); shelfGrp.add(shelf);
  }

  // ═══════════════════════════════════════════════════════════════
  // WINDOW (on the right wall)
  // ═══════════════════════════════════════════════════════════════
  const winW = 1.0, winH = 1.2;
  const winX = sx + hw + 0.01;
  const winY = floorY + 1.8;
  const winZ = sz;

  // Window frame (attached to studyWalls)
  for (const dx of [-winW / 2, winW / 2]) {
    const wf2 = box(0.05, winH, 0.05, MATS.window);
    wf2.position.set(winX, winY, winZ + dx);
    addTo('studyWalls', wf2); wallsGrp.add(wf2);
  }
  for (const dz of [-winH / 2, winH / 2]) {
    const wf3 = box(winW, 0.05, 0.05, MATS.window);
    wf3.position.set(winX, winY + dz, winZ);
    addTo('studyWalls', wf3); wallsGrp.add(wf3);
  }
  // Glass
  const glassMat = new THREE.MeshStandardMaterial({
    color: 0xaaccff, roughness: 0.1, metalness: 0.1,
    transparent: true, opacity: 0.35,
  });
  const glass = box(winW - 0.2, winH - 0.2, 0.02, glassMat);
  glass.position.set(winX, winY, winZ);
  addTo('studyWalls', glass); wallsGrp.add(glass);
}
